import{c as t,Q as o,j as a,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Quickstart","description":"From passkey to first encrypted buy.","frontmatter":{"title":"Quickstart","description":"From passkey to first encrypted buy."},"headers":[],"relativePath":"get-started/quickstart.md","filePath":"get-started/quickstart.md","lastUpdated":1778986743000}'),n={name:"get-started/quickstart.md"};function s(i,e,l,u,c,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="quickstart" tabindex="-1">Quickstart <a class="header-anchor" href="#quickstart" aria-label="Permalink to &quot;Quickstart&quot;">​</a></h1><p>One passkey. One encrypted buy. We&#39;ll do it in HavenBot (the in-dashboard copilot) because it&#39;s the surface with the lowest setup cost — no terminal, no host config, no Telegram link.</p><p>Once you&#39;re done, the <a href="/get-started/choosing-a-surface">Choosing a surface</a> page shows how to layer in the other surfaces (MCP, Telegram, hosted checkout) without re-onboarding.</p><p>The five steps below:</p><ol><li>Sign in with a passkey.</li><li>Open HavenBot.</li><li>Run the onboarding wizard (welcome → funding → first buy).</li><li>Pick your tier (optional).</li><li>Pick more surfaces (optional).</li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>A modern browser that supports WebAuthn passkeys (Chrome, Edge, Safari, Firefox — current versions).</li><li>A device with a biometric authenticator (Touch ID, Windows Hello, Android fingerprint) <strong>or</strong> a YubiKey-style hardware key. iCloud Keychain / Google Password Manager / 1Password also work.</li><li>A small amount of test mhUSDC (we&#39;ll show you the faucet step below). On production, an on-ramp swap is one click — testnet uses a free faucet.</li></ul><div class="tip custom-block"><p class="custom-block-title">Testnet vs production</p><p>The walkthrough below uses Arbitrum Sepolia (testnet). The <code>muhaven.app</code> dashboard supports both networks; switch in the top-right network selector. Steps are identical — only the funding source differs (faucet vs. on-ramp).</p></div><h2 id="step-1-—-sign-in-with-a-passkey" tabindex="-1">Step 1 — Sign in with a passkey <a class="header-anchor" href="#step-1-—-sign-in-with-a-passkey" aria-label="Permalink to &quot;Step 1 — Sign in with a passkey&quot;">​</a></h2><p>Open <a href="https://muhaven.app" target="_blank" rel="noreferrer">https://muhaven.app</a> and click <strong>Sign in</strong>.</p><ol><li>A passkey dialog appears. Pick <strong>Create a new passkey</strong> (or <strong>Use an existing one</strong> if you&#39;ve signed in before).</li><li>Approve with Touch ID / Windows Hello / your hardware key.</li><li>The first sign-in deploys your <strong>MuHaven wallet</strong> (a ZeroDev-powered smart account) in the background, paymaster-sponsored. You don&#39;t need to do anything; just wait for the dashboard to load.</li></ol><p>You now have a <strong>passkey-bound MuHaven wallet</strong> on Arbitrum Sepolia. No seed phrase. No private key on your device.</p><div class="warning custom-block"><p class="custom-block-title">One passkey, one role</p><p>A given passkey can be either an investor <em>or</em> an issuer, not both. If you plan to be an issuer, register a second passkey for that purpose — see <a href="/get-started/investor-vs-issuer">Investor vs issuer</a>.</p></div><h2 id="step-2-—-run-the-onboarding-wizard" tabindex="-1">Step 2 — Run the onboarding wizard <a class="header-anchor" href="#step-2-—-run-the-onboarding-wizard" aria-label="Permalink to &quot;Step 2 — Run the onboarding wizard&quot;">​</a></h2><p>In the sidebar, click <strong>Agent</strong> — that lands you on <code>/agent</code>. To go through the first-time wizard, navigate to <strong><code>/agent/onboarding</code></strong> (the dashboard doesn&#39;t auto-redirect; type the URL or use the <strong>Run onboarding</strong> entry in the page menu).</p><p>The wizard walks you through:</p><ol><li><strong>Welcome</strong> — a short explainer with the &quot;sealed-glass-envelope&quot; copy (your balances are encrypted; you hold the key).</li><li><strong>Funding</strong> — a button that takes you to the testnet mhUSDC faucet. Grab some test stablecoin and come back.</li><li><strong>First buy</strong> — pick a token from the list of active RWAs, enter an amount, and click <strong>Continue</strong>.</li></ol><p>The wizard skips steps you&#39;ve already done — if your MuHaven wallet already holds positions, you&#39;ll land on the celebrate screen instead.</p><p>See <a href="/havenbot/onboarding">HavenBot onboarding</a> for the full walkthrough.</p><h2 id="step-3-—-have-your-first-conversation" tabindex="-1">Step 3 — Have your first conversation <a class="header-anchor" href="#step-3-—-have-your-first-conversation" aria-label="Permalink to &quot;Step 3 — Have your first conversation&quot;">​</a></h2><p>After onboarding, you&#39;re in HavenBot proper at <code>/agent</code>. Try one of:</p><ul><li>&quot;Show me my portfolio.&quot;</li><li>&quot;What&#39;s the current NAV of <code>&lt;TOKEN&gt;</code>?&quot;</li><li>&quot;Buy 50 mhUSDC of <code>&lt;TOKEN&gt;</code>.&quot;</li></ul><p>For read-only questions (&quot;show me&quot;, &quot;what&#39;s&quot;), HavenBot answers in-line — no confirmation needed.</p><p>For state-changing actions (&quot;buy&quot;, &quot;claim&quot;, &quot;set policy&quot;), HavenBot opens a <strong>ConfirmModal</strong>:</p><ol><li>Cleartext preview of what&#39;s about to happen (amount, token, estimated shares).</li><li>Your MuHaven wallet signs the UserOp with your scoped session key (default 1-hour TTL).</li><li>A small toast says &quot;Signed → Bundler → Settling…&quot; and then &quot;Settled, see Arbiscan.&quot;</li></ol><p>Welcome to MuHaven. You just made a confidential RWA purchase: the cleartext amount <strong>never</strong> left your browser. On-chain, only ciphertext.</p><h2 id="step-4-—-pick-your-tier-optional-but-recommended" tabindex="-1">Step 4 — Pick your tier (optional, but recommended) <a class="header-anchor" href="#step-4-—-pick-your-tier-optional-but-recommended" aria-label="Permalink to &quot;Step 4 — Pick your tier (optional, but recommended)&quot;">​</a></h2><p>By default you&#39;re in <strong>Advisory</strong> tier — every action needs a passkey confirmation. After ≥5 confirmed actions you&#39;ll be offered a graduation to <strong>Confirm-per-action</strong> (session-key signs without re-prompting your passkey for 1 hour). Power users can opt into <strong>Policy-bound</strong> (the agent acts within your encrypted thresholds without per-action confirmation; breaches trigger a <code>RiskBreach</code> and an auto-pause).</p><p>Set your tier from <code>Sidebar → Policy → Tier</code>, or ask HavenBot: <em>&quot;Switch me to Confirm-per-action.&quot;</em> See <a href="/policy/tiered-autonomy">Tiered autonomy</a> for the full ladder.</p><h2 id="step-5-—-pick-more-surfaces-optional" tabindex="-1">Step 5 — Pick more surfaces (optional) <a class="header-anchor" href="#step-5-—-pick-more-surfaces-optional" aria-label="Permalink to &quot;Step 5 — Pick more surfaces (optional)&quot;">​</a></h2><p>You&#39;re done. From here you can:</p><ul><li><strong>Continue in HavenBot.</strong> Read <a href="/havenbot/conversations">HavenBot conversations &amp; confirmations</a> and the <a href="/havenbot/investor-playbook">investor playbook</a>.</li><li><strong>Install <code>@muhaven/mcp</code></strong> to talk to MuHaven from Claude Code / Claude Desktop / Cursor with your own LLM. See <a href="/mcp/install">MCP install</a>.</li><li><strong>Link your Telegram</strong> for phone-first access with three-tier confirmation. See <a href="/openclaw/telegram-bot">Telegram bot</a>.</li><li><strong>(Issuers only)</strong> create a hosted checkout link to sell to non-customer buyers. See <a href="/checkout/for-issuers">Hosted checkout for issuers</a>.</li></ul><div class="tip custom-block"><p class="custom-block-title">One account, every surface</p><p>Your passkey-bound MuHaven wallet is the same account across all four surfaces. Linking your Telegram, authorizing the MCP broker, and minting a checkout link all bind back to the same on-chain identity — and the same audit log.</p></div><h2 id="if-something-went-wrong" tabindex="-1">If something went wrong <a class="header-anchor" href="#if-something-went-wrong" aria-label="Permalink to &quot;If something went wrong&quot;">​</a></h2><ul><li><strong>Passkey dialog didn&#39;t appear</strong> — check that your browser is up-to-date and that hardware-backed credentials are enabled. iCloud Keychain users on macOS need to enable it in System Settings → Passwords.</li><li><strong>Sign-in succeeded but the dashboard is empty</strong> — verify you&#39;re on Arbitrum Sepolia. Switch the network selector top-right.</li><li><strong>Faucet wouldn&#39;t dispense</strong> — testnet faucets are rate-limited. Wait and retry, or use the on-ramp on production.</li><li><strong>ConfirmModal shows an encrypted handle instead of a number</strong> — that&#39;s the policy gate&#39;s safety net. Re-run the action; if it persists, see <a href="/havenbot/troubleshooting">HavenBot troubleshooting</a>.</li><li><strong>Everything is unreachable</strong> — check status with the MuHaven team.</li></ul>',35)])])}const g=t(n,[["render",s]]);export{p as __pageData,g as default};
